344	## Phase 3: Web — shared `ClientAuthBridge` + `/desktop/auth` route
345	
346	### Overview
347	
348	The existing `cli-auth-client.tsx` and a new desktop bridge share ~90% of their logic: same `useAuth` flow, same status machine, same Suspense wrapper, same error UI. Rather than duplicate, extract a shared `ClientAuthBridge` component that both CLI and desktop consume. This collapses two sibling components into one and makes the pattern reusable for any future OAuth bridge (e.g., VS Code extension, other CLIs).
349	
350	### Changes Required
351	
352	#### 3.1 Extract shared `ClientAuthBridge`
353	
354	**File**: `apps/app/src/app/(app)/(user)/(pending-not-allowed)/_components/client-auth-bridge.tsx` (new)
355	
356	Generic bridge taking a `buildRedirectUrl` callback and an optional `jwtTemplate`. Contains all the status/UI logic from the current `cli-auth-client.tsx`.
357	
358	```tsx
359	"use client";
360	
361	import { useAuth } from "@vendor/clerk/client";
362	import { useSearchParams } from "next/navigation";
363	import { Suspense, useEffect, useState, type ReactNode } from "react";
364	
365	export interface ClientAuthBridgeProps {
366	  /**
367	   * Build the redirect URL given the Clerk token.
368	   * Return null to signal invalid/missing required params — bridge renders error.
369	   */
370	  buildRedirectUrl: (args: {
371	    token: string;
372	    searchParams: URLSearchParams;
373	  }) => string | null;
374	
375	  /** Optional Clerk JWT template. Omit for default session JWT (CLI uses default). */
376	  jwtTemplate?: string;
377	
378	  /** Title shown while authenticating/redirecting. */
379	  title: string;
380	
381	  /** Body copy under the title. */
382	  subtitle: string;
383	
384	  /** Optional loading UI override (defaults to title+subtitle). */
385	  fallback?: ReactNode;
386	}
387	
388	function BridgeContent(props: ClientAuthBridgeProps) {
389	  const { getToken, isSignedIn, isLoaded } = useAuth();
390	  const searchParams = useSearchParams();
391	  const [status, setStatus] = useState<"loading" | "redirecting" | "error">(
392	    "loading"
393	  );
394	
395	  useEffect(() => {
396	    if (!isLoaded || !isSignedIn) return;
397	    void (async () => {
398	      try {
399	        const token = await getToken(
400	          props.jwtTemplate ? { template: props.jwtTemplate } : undefined
401	        );
402	        if (!token) {
403	          setStatus("error");
404	          return;
405	        }
406	        const url = props.buildRedirectUrl({ token, searchParams });
407	        if (!url) {
408	          setStatus("error");
409	          return;
410	        }
411	        setStatus("redirecting");
412	        window.location.href = url;
413	      } catch {
414	        setStatus("error");
415	      }
416	    })();
417	  }, [isLoaded, isSignedIn, getToken, props, searchParams]);
418	
